1	type Item = { type: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: QuoteStep[];
6	};
7	type QuoteResult = { premium: number };
8	
9	const PROCESSING_FEE = 5;
10	const FIRST_INSURANCE_SURCHARGE = 0.1;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	};
19	
20	const itemPremium = (item: Item): number => {
21	  const base = BASE_PREMIUMS[item.type];
22	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE;
23	  return base + firstInsuranceSurcharge;
24	};
25	
26	const quotePremium = (step: QuoteStep): QuoteResult => {
27	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
28	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
29	};
30	
31	export const run = (scenario: Scenario): { results: QuoteResult[] } => {
32	  return { results: scenario.steps.map(quotePremium) };
33	};
